import React from 'react';
import { motion } from 'framer-motion';
import { CheckCircle, Shield, Award } from 'lucide-react';

const About = () => {
  return (
    <section id="about" className="py-24 bg-white relative">
      <div className="max-w-7xl mx-auto px-6">
        <div className="flex flex-col lg:flex-row items-center gap-16">

          {/* Visual Side */}
          <div className="w-full lg:w-1/2 relative">
            <motion.div 
              initial={{ opacity: 0, x: -50 }}
              whileInView={{ opacity: 1, x: 0 }}
              viewport={{ once: true }}
              transition={{ duration: 0.8 }}
              className="relative rounded-3xl overflow-hidden aspect-[4/3] md:aspect-[5/4] shadow-2xl group"
            >
              {/* Abstract structural gradient representing institution */}
              <div className="absolute inset-0 bg-gradient-to-br from-primary via-slate-800 to-indigo-900 z-0 group-hover:scale-105 transition-transform duration-700"></div>

              {/* Overlay architectural lines/grid for modern feel */}
              <div className="absolute inset-0 bg-[url('data:image/svg+xml;base64,PHN2ZyB4bWxucz0iaHR0cDovL3d3dy53My5vcmcvMjAwMC9zdmciIHdpZHRoPSIyMCIgaGVpZ2h0PSIyMCI+PHBhdGggZD0iTTAgMGgyMHYyMEgweiIgZmlsbD0ibm9uZSIvPjxwYXRoIGQ9Ik0wIDE5aDIwTTE5IDB2MjAiIHN0cm9rZT0icmdiYSgyNTUsIDI1NSwgMjU1LCAwLjAxKSIgc3Ryb2tlLXdpZHRoPSIxIi8+PC9zdmc+')] opacity-50 z-10"></div>

              <div className="relative z-20 h-full flex flex-col justify-end p-8 text-white">
                <div className="w-20 h-1 bg-secondary mb-4 rounded-full"></div>
                <h3 className="text-3xl font-heading font-bold mb-2">Legacy of Excellence</h3>
                <p className="text-white/80">Guiding aspirants since 1985</p>
              </div>

              {/* Floating Stat Card */}
              <motion.div 
                animate={{ y: [0, -10, 0] }}
                transition={{ repeat: Infinity, duration: 4, ease: "easeInOut" }}
                className="absolute top-8 right-8 glassmorphism text-primary rounded-2xl p-4 shadow-xl flex items-center space-x-3 z-30"
              >
                <div className="w-12 h-12 rounded-full bg-secondary text-white flex items-center justify-center">
                  <Award size={24} />
                </div>
                <div>
                  <p className="text-xl font-bold font-heading">38+</p>
                  <p className="text-xs font-semibold text-slate-500 uppercase tracking-wider">Years Exp.</p>
                </div>
              </motion.div>
            </motion.div>
          </div>

          {/* Text Side */}
          <div className="w-full lg:w-1/2">
            <motion.div
              initial={{ opacity: 0, x: 50 }}
              whileInView={{ opacity: 1, x: 0 }}
              viewport={{ once: true }}
              transition={{ duration: 0.8 }}
            >
              <h4 className="text-secondary font-bold uppercase tracking-widest text-sm mb-3">About Sriram's IAS</h4>
              <h2 className="text-4xl md:text-5xl font-heading font-bold text-primary mb-6 leading-tight">
                Empowering Minds, <br />
                <span className="text-transparent bg-clip-text bg-gradient-to-r from-primary to-secondary">Building The Nation.</span>
              </h2>

              <p className="text-slate-600 text-lg mb-8 leading-relaxed">
                Founded by Prof. Srirangam, Sriram's IAS has been the beacon of quality coaching for the Civil Services Examination. We don't just teach the syllabus; we develop the analytical aptitude required for a civil servant.
              </p>

              <div className="space-y-4 mb-10">
                {[
                  'India\'s most trusted faculty for General Studies',
                  'Comprehensive study material curated by experts',
                  'Personalized mentorship and strict evaluation system',
                  'Consistently producing All India Rankers every year'
                ].map((item, idx) => (
                  <div key={idx} className="flex items-start">
                    <CheckCircle className="text-secondary mt-1 mr-3 flex-shrink-0" size={20} />
                    <span className="text-slate-700 font-medium">{item}</span>
                  </div>
                ))}
              </div>

              <div className="flex items-center space-x-6">
                <button className="bg-primary hover:bg-slate-800 text-white px-8 py-3.5 rounded-full font-bold transition-all shadow-lg hover:-translate-y-1">
                  Read Our Story
                </button>
                <div className="flex items-center text-slate-500 font-medium text-sm">
                  <Shield size={20} className="text-emerald-500 mr-2" /> 
                  ISO 9001:2015 Certified
                </div>
              </div>
            </motion.div>
          </div>
        </div>
      </div>
    </section>
  );
};

export default About;

import React from 'react';
import { motion } from 'framer-motion';
import { ArrowRight, PhoneCall } from 'lucide-react';

const Contact = () => {
  return (
    <section className="py-24 bg-white relative overflow-hidden">
      {/* Abstract Background Design */}
      <div className="absolute inset-0 z-0">
         <div className="absolute top-0 right-0 w-1/2 h-full bg-gradient-to-l from-blue-50 to-transparent skew-x-12 origin-top-right"></div>
      </div>

      <div className="max-w-5xl mx-auto px-6 relative z-10">
        <motion.div
          initial={{ opacity: 0, scale: 0.95 }}
          whileInView={{ opacity: 1, scale: 1 }}
          viewport={{ once: true }}
          className="bg-white rounded-[3rem] p-10 md:p-16 shadow-[0_20px_60px_rgba(10,37,64,0.08)] overflow-hidden relative border border-slate-100"
        >
          {/* Decorative glowing orb inside the box */}
          <div className="absolute top-0 right-0 w-64 h-64 bg-orange-200 rounded-full blur-[80px] opacity-40 translate-x-1/3 -translate-y-1/3"></div>
          <div className="absolute bottom-0 left-0 w-64 h-64 bg-blue-200 rounded-full blur-[80px] opacity-30 -translate-x-1/3 translate-y-1/3"></div>

          <div className="relative z-10 text-center">
            <h2 className="text-4xl md:text-5xl font-heading font-extrabold text-primary mb-6">
              Ready to claim your spot in <br className="hidden md:block"/> the <span className="text-transparent bg-clip-text bg-gradient-to-r from-secondary to-orange-400">Civil Services?</span>
            </h2>
            <p className="text-slate-500 text-lg mb-10 max-w-2xl mx-auto">
              Join the new batch starting this month. Secure your admission and get access to exclusive early-bird study materials and mentorship calls.
            </p>

            <div className="flex flex-col sm:flex-row items-center justify-center space-y-4 sm:space-y-0 sm:space-x-6">
              <button className="bg-gradient-to-r from-secondary to-orange-500 hover:from-orange-500 hover:to-secondary text-white px-10 py-4 rounded-full font-bold text-lg shadow-[0_10px_20px_rgba(255,107,0,0.2)] hover:shadow-[0_15px_30px_rgba(255,107,0,0.4)] transition-all transform hover:scale-105 flex items-center justify-center w-full sm:w-auto">
                Apply for Admission <ArrowRight className="ml-2" />
              </button>

              <button className="bg-white hover:bg-slate-50 text-slate-700 border border-slate-200 px-8 py-4 rounded-full font-bold text-lg shadow-sm hover:shadow-md transition-all flex items-center justify-center w-full sm:w-auto">
                <PhoneCall size={20} className="mr-2 text-primary" /> Request Callback
              </button>
            </div>

            <p className="text-slate-500 text-sm mt-8">
              Still have doubts? Call us directly at <a href="tel:+919876543210" className="text-secondary font-bold hover:underline">+91 98765 43210</a>
            </p>
          </div>
        </motion.div>
      </div>
    </section>
  );
};

export default Contact;

import React from 'react';
import { motion } from 'framer-motion';
import { BookOpen, Target, Clock, Star, ArrowRight } from 'lucide-react';

const courses = [
  {
    id: 1,
    title: 'UPSC GS Foundation (Prelims+Mains)',
    duration: '10 Months',
    mode: 'Offline / Online',
    rating: '4.9',
    icon: <Target className="w-8 h-8 text-secondary" />,
    color: 'from-blue-500/20 to-indigo-500/20',
    border: 'group-hover:border-blue-500/30'
  },
  {
    id: 2,
    title: 'Optional Subjects Core Program',
    duration: '5 Months',
    mode: 'Offline / Online',
    rating: '4.8',
    icon: <BookOpen className="w-8 h-8 text-orange-500" />,
    color: 'from-orange-500/20 to-red-500/20',
