      <div className="absolute inset-0 bg-slate-50/90 z-10 md:hidden border-b border-slate-100"></div>

      <div className="max-w-7xl mx-auto px-6 relative z-20 w-full flex flex-col md:flex-row items-center">

        {/* Text Content */}
