          <motion.div
            initial={{ opacity: 0, y: 30 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.8 }}
          >
            <div className="inline-flex items-center space-x-2 bg-white/70 backdrop-blur-md px-4 py-2 rounded-full mb-6 border border-blue-100 shadow-[0_4px_15px_rgba(59,130,246,0.1)]">
              <Award size={16} className="text-secondary" />
              <span className="text-sm font-semibold tracking-wide text-slate-700">NO.1 IAS COACHING INSTITUTE IN INDIA</span>
